import java.io.IOException;

public class SecureCommandExecutionExample {

    public static void main(String[] args) {
        try {
            String userInput = "www.example.com";

            // Sanitize user input by only allowing alphanumeric characters
            if (!userInput.matches("[a-zA-Z0-9.]+")) {
                throw new IllegalArgumentException("Invalid input");
            }

            // Construct the command and its arguments separately
            String[] command = {"ping", userInput};

            ProcessBuilder processBuilder = new ProcessBuilder(command);

            Process process = processBuilder.start();

            // Read output of the command
        } catch (IOException | IllegalArgumentException e) {
            System.out.println("An error occurred: " + e.getMessage());
        }
    }
}

